scwin.f_noSelectScNm = function () {
    var row = ds_retrieveStevedoring.getRowPosition();
    var status = ds_retrieveStevedoring.getRowStatus(row);

    if (status == "C") {
        gr_retrieveStevedoring.setCellReadOnly(row, 'goodsNm', false);
        gr_retrieveStevedoring.setCellReadOnly(row, 'adptStDt', false);
    }
    else {
        gr_retrieveStevedoring.setCellReadOnly(row, 'goodsNm', true);
        gr_retrieveStevedoring.setCellReadOnly(row, 'adptStDt', true);
    }

    var rowData = ds_retrieveStevedoring.getCellData(row, "adptEndDt");

    if (status == "R" && rowData != "99999999") {
        gr_retrieveStevedoring.setCellReadOnly(row, 'basisUnitCd', true);
        gr_retrieveStevedoring.setCellReadOnly(row, 'bas004', true);
        gr_retrieveStevedoring.setCellReadOnly(row, 'bas005', true);
        gr_retrieveStevedoring.setCellReadOnly(row, 'bas006', true);
        gr_retrieveStevedoring.setCellReadOnly(row, 'scBasisUnitCd', true);
        gr_retrieveStevedoring.setCellReadOnly(row, 'scBas004', true);
        gr_retrieveStevedoring.setCellReadOnly(row, 'scBas005', true);
        gr_retrieveStevedoring.setCellReadOnly(row, 'scBas006', true);
        gr_retrieveStevedoring.setCellReadOnly(row, 'adptEndDt', true);
        gr_retrieveStevedoring.setCellReadOnly(row, 'wageAgrmntDt', true);
        gr_retrieveStevedoring2.setReadOnly("grid", true);
    }
    else {
        gr_retrieveStevedoring.setCellReadOnly(row, 'basisUnitCd', false);
        gr_retrieveStevedoring.setCellReadOnly(row, 'bas004', false);
        gr_retrieveStevedoring.setCellReadOnly(row, 'bas005', false);
        gr_retrieveStevedoring.setCellReadOnly(row, 'bas006', false);
        gr_retrieveStevedoring.setCellReadOnly(row, 'scBasisUnitCd', false);
        gr_retrieveStevedoring.setCellReadOnly(row, 'scBas004', false);
        gr_retrieveStevedoring.setCellReadOnly(row, 'scBas005', false);
        gr_retrieveStevedoring.setCellReadOnly(row, 'scBas006', false);
        gr_retrieveStevedoring.setCellReadOnly(row, 'adptEndDt', false);
        gr_retrieveStevedoring.setCellReadOnly(row, 'wageAgrmntDt', false);
        //gr_retrieveStevedoring2.Editable = true;
        gr_retrieveStevedoring2.setReadOnly("grid", false);
    }
}

