    var vWageAgrmntDt = ds_retrieveStevedoring.getCellData(ds_retrieveStevedoring.getRowPosition(), "wageAgrmntDt");	//원인노임협약일자 
    var vGoodsCd = dma_oGDS_view_cond.get("goodsCd");			//품목코드
    var vGoodsNm = dma_oGDS_view_cond.get("goodsNm");			//품명 
    /*
        window.showModalDialog("op_403_01_02p.jsp?districtCd="+vDistrictCd+
                                                "&wrkMthdCd="+vWrkMthdCd+
                                                "&wageAgrmntDt="+vWageAgrmntDt+
                                                "&goodsCd="+vGoodsCd+
                                                "&goodsNm="+vGoodsNm+
                                                "&adptStDt="+vAdptStDt
                                ,window,"dialogHeight:300px;dialogWidth:600px;");        
    */

    var win_url = "/ui/ds/op/adjmbd/wageadjmproc/op_403_01_02p.xml";

    var opts = scwin.opts || {};
    opts.modal = true;
    opts.type = "browserPopup";
    opts.id = scwin.popupID || "pupup";
    opts.width = 800;
    opts.height = 300;
    opts.popupName = "하역노임기본요율복사";

