        goodsNm: vGoodsNm
    }

    rtnList = await $c.win.openPopup(win_url, opts, param);
}

scwin.f_amtNrt = async function (row, colid) {
debugger;

    var basisWrkStpCd = ds_retrieveStevedoring2.getCellData(row, "basisWrkStpCd");

    if (colid == "basisUprAmt") {
        var amt = ds_retrieveStevedoring2.getCellData(row, colid);
        var scRt = scwin.f_basicAmt(basisWrkStpCd);
        var basicRt = 0;
        if (amt != 0 && scRt != 0) {
            basicRt = parseFloat(amt / scRt) * 100;
        } else if (amt != 0 && scRt == 0) {
            basicRt = "Infinity";
        }

        var valueNull = ds_retrieveStevedoring2.getCellData(row, "basisWrkStpCd");

        if (valueNull != "") {
            if (! await scwin.f_checkRtLength(colid, basicRt)) {
                return;
            }
            ds_retrieveStevedoring2.setCellData(row, "basisUprRt", Number(basicRt).toFixed(2));
            scwin.f_amtNrt(row, "jangbiAmt1");
            scwin.f_amtNrt(row, "jangbiAmt2");
            scwin.f_amtNrt(row, "jangbiAmt3");
        }
        else if (valueNull == "") {
            //ds_retrieveStevedoring2.setCellData(row, "basisUprRt", "");
            ds_retrieveStevedoring2.setCellData(row, "basisUprRt", 0);

        }
    }

    if (colid == "basisUprRt") {
        var amt = ds_retrieveStevedoring2.getCellData(row, colid);
        var scRt = scwin.f_basicAmt(basisWrkStpCd);
        var basicAmt = parseFloat(amt * scRt) / 100;
        ds_retrieveStevedoring2.setCellData(row, "basisUprAmt", basicAmt.toFixed(2));
        scwin.f_amtNrt(row, "jangbiRt1");
    }

    if (colid == "scBasisUprAmt") {
        var amt = ds_retrieveStevedoring2.getCellData(row, colid);
        var scRt = scwin.f_scAmt(basisWrkStpCd);
        var basicRt = 0;
        if (amt != 0 && scRt != 0) {
            basicRt = parseFloat(amt / scRt) * 100;
        } else if (amt != 0 && scRt == 0) {
            basicRt = "Infinity";
        }

        var valueNull = ds_retrieveStevedoring2.getCellData(row, "basisWrkStpCd");

        if (valueNull != "") {
            if (! await scwin.f_checkRtLength(colid, basicRt)) return;
            ds_retrieveStevedoring2.setCellData(row, "scBasisUprRt", Number(basicRt).toFixed(2));
            scwin.f_amtNrt(row, "jangbiAmt2");
        } else if (valueNull == "") {
            //ds_retrieveStevedoring2.setCellData(row, "scBasisUprRt", "");
            ds_retrieveStevedoring2.setCellData(row, "scBasisUprRt", 0);
        }
    }

    if (colid == "scBasisUprRt") {
        var amt = ds_retrieveStevedoring2.getCellData(row, colid);
        var scRt = scwin.f_scAmt(basisWrkStpCd);
        var scAmt = parseFloat(amt * scRt) / 100;
        ds_retrieveStevedoring2.setCellData(row, "scBasisUprAmt", Number(scAmt).toFixed(2));
        scwin.f_amtNrt(row, "jangbiRt2");
    }

    if (colid == "jangbiAmt1") {
        var basicAmt = ds_retrieveStevedoring2.getCellData(row, "basisUprAmt");
        var jangbiAmt = ds_retrieveStevedoring2.getCellData(row, colid);
        if (jangbiAmt != 0) {
            var Rt = parseFloat(jangbiAmt / basicAmt) * 100;
            if (!(await scwin.f_checkBasicAmtNull(colid))) return;

            var value = Number(Rt).toFixed(0);
            if (value.length >= 4) {
                $c.win.alert("상세작업단계별 기본요율의 장비적용율이 1000%를 초과하였습니다.");
                ds_retrieveStevedoring2.setCellData(row, "jangbiAmt1", 0);
            }
            else {
                ds_retrieveStevedoring2.setCellData(row, "jangbiRt1", Rt);
            }
        }
    }

    if (colid == "jangbiAmt2") {
        var basicAmt = ds_retrieveStevedoring2.getCellData(row, "basisUprAmt");
        var jangbiAmt = ds_retrieveStevedoring2.getCellData(row, colid);
        if (jangbiAmt != 0) {
            var Rt = parseFloat(jangbiAmt / basicAmt) * 100;
            if (!(await scwin.f_checkBasicAmtNull(colid))) return;

            var value = Number(Rt).toFixed(0);
            if (value.length >= 4) {
                $c.win.alert("상세작업단계별 기본요율의 장비적용율이 1000%를 초과하였습니다.");
                ds_retrieveStevedoring2.setCellData(row, "jangbiAmt2", 0);
            }
            else {
                ds_retrieveStevedoring2.setCellData(row, "jangbiRt2", Rt);
            }
        }
    }

    if (colid == "jangbiAmt3") {
        var basicAmt = ds_retrieveStevedoring2.getCellData(row, "basisUprAmt");
        var jangbiAmt = ds_retrieveStevedoring2.getCellData(row, colid);
        if (jangbiAmt != 0) {
            var Rt = parseFloat(jangbiAmt / basicAmt) * 100;
            if (!(await scwin.f_checkBasicAmtNull(colid))) return;

            var value = Number(Rt).toFixed(0);
            if (value.length >= 4) {
                $c.win.alert("상세작업단계별 기본요율의 장비적용율이 1000%를 초과하였습니다.");
                ds_retrieveStevedoring2.setCellData(row, "jangbiAmt3", 0);
            }
            else {
                ds_retrieveStevedoring2.setCellData(row, "jangbiRt3", Rt);
            }
        }
    }

    if (colid == "jangbiRt1") {
        var basicAmt = ds_retrieveStevedoring2.getCellData(row, "basisUprAmt");
        var jangbiRt = ds_retrieveStevedoring2.getCellData(row, colid);
        var Rt = parseFloat(basicAmt * jangbiRt) / 100;
        if (!(await scwin.f_checkBasicAmtNull(colid))) return;
        ds_retrieveStevedoring2.setCellData(row, "jangbiAmt1", Number(Rt).toFixed(2));
    }

    if (colid == "jangbiRt2") {
        var basicAmt = ds_retrieveStevedoring2.getCellData(row, "basisUprAmt");
        var jangbiRt = ds_retrieveStevedoring2.getCellData(row, colid);
        var Rt = parseFloat(basicAmt * jangbiRt) / 100;
        if (!(await scwin.f_checkBasicAmtNull(colid))) return;
        ds_retrieveStevedoring2.setCellData(row, "jangbiAmt2", Number(Rt).toFixed(2));
    }

    if (colid == "jangbiRt3") {
        var basicAmt = ds_retrieveStevedoring2.getCellData(row, "basisUprAmt");
        var jangbiRt = ds_retrieveStevedoring2.getCellData(row, colid);
        var Rt = parseFloat(basicAmt * jangbiRt) / 100;
        if (!(await scwin.f_checkBasicAmtNull(colid))) return;
        ds_retrieveStevedoring2.setCellData(row, "jangbiAmt3", Number(Rt).toFixed(2));
    }
}

