scwin.f_checkRtLength = async function (colid, basicRt) {

    var value = Number(basicRt).toFixed(0);

    if (value.length >= 4) {
        ds_retrieveStevedoring2.setCellData(ds_retrieveStevedoring2.getRowPosition(), colid, 0);

        if (value == "Infinity") {
            $c.win.alert("하역노임기본요율 기본요율에 요율을 입력하십시오.");
        }
        else {
            $c.win.alert("상세작업단계별 기본요율의 적용율이 1000%를 초과하였습니다.");
        }

        return false;
    }
    return true;
}

