scwin.f_CreateCommAuto = function () {
    var cntRow = ds_goodsCd.getRowCount();
    scwin.rowFlag = "1";

    ds_retrieveStevedoring2.removeAll();
    ds_retrieveStevedoring3.removeAll();

    for (var i = 0; i < cntRow; i++) {
        var valueCode = ds_goodsCd.getCellData(i, "code");
        var valueName = ds_goodsCd.getCellData(i, "name");
        var over = ds_retrieveStevedoring.getMatchedIndex("goodsCd", valueCode);

        var adptEndDt = ds_retrieveStevedoring.getCellData(over, "adptEndDt");
        var nowStDt = ds_retrieveStevedoring.getCellData(ds_retrieveStevedoring.getRowPosition(), "adptStDt");
        var nowAgrmntDt = ds_retrieveStevedoring.getCellData(ds_retrieveStevedoring.getRowPosition(), "wageAgrmntDt");

        if (over == 0 || (over != 0 && adptEndDt != "99999999")) {
            ds_retrieveStevedoring.insertRow();

            gr_retrieveStevedoring.setFocusedCell(ds_retrieveStevedoring.getRowCount() - 1, 0);

            ds_retrieveStevedoring.setCellData(ds_retrieveStevedoring.getRowPosition(), "districtCd", lc_con_districtCd.getValue());
            ds_retrieveStevedoring.setCellData(ds_retrieveStevedoring.getRowPosition(), "goodsCd", valueCode);
            ds_retrieveStevedoring.setCellData(ds_retrieveStevedoring.getRowPosition(), "goodsNm", valueName);
            ds_retrieveStevedoring.setCellData(ds_retrieveStevedoring.getRowPosition(), "upGoodsNm", "");
            ds_retrieveStevedoring.setCellData(ds_retrieveStevedoring.getRowPosition(), "wrkMthdCd", lc_con_wrkMthdCd.getValue());
            ds_retrieveStevedoring.setCellData(ds_retrieveStevedoring.getRowPosition(), "selpchItemCd", "0119");
            ds_retrieveStevedoring.setCellData(ds_retrieveStevedoring.getRowPosition(), "basisUnitCd", "TON");
            ds_retrieveStevedoring.setCellData(ds_retrieveStevedoring.getRowPosition(), "bas004", 0);
            ds_retrieveStevedoring.setCellData(ds_retrieveStevedoring.getRowPosition(), "bas005", 0);
            ds_retrieveStevedoring.setCellData(ds_retrieveStevedoring.getRowPosition(), "bas006", "");
            ds_retrieveStevedoring.setCellData(ds_retrieveStevedoring.getRowPosition(), "scBasisUnitCd", "TON");
            ds_retrieveStevedoring.setCellData(ds_retrieveStevedoring.getRowPosition(), "scBas004", 0);
            ds_retrieveStevedoring.setCellData(ds_retrieveStevedoring.getRowPosition(), "scBas005", 0);
            ds_retrieveStevedoring.setCellData(ds_retrieveStevedoring.getRowPosition(), "scBas006", 0);
            ds_retrieveStevedoring.setCellData(ds_retrieveStevedoring.getRowPosition(), "adptStDt", nowStDt);
            ds_retrieveStevedoring.setCellData(ds_retrieveStevedoring.getRowPosition(), "adptEndDt", "99999999");
            ds_retrieveStevedoring.setCellData(ds_retrieveStevedoring.getRowPosition(), "wageAgrmntDt", nowAgrmntDt);
            ds_retrieveStevedoring.setCellData(ds_retrieveStevedoring.getRowPosition(), "wrkStpCd", "");
        }
    }

    spa_cnt1.setValue(ds_retrieveStevedoring.getRowCount());

    //        rowFlag = "";
}

