scwin.sbm_save_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code == 0) {
        scwin.rowFlag = "";  // 초기화	
        $c.win.alert(MSG_CM_INF_001);	// 성공적으로 저장하였습니다
        // scwin.f_Retrieve();
    } else {
        if (e.responseJSON.resultDataSet[1] != null && e.responseJSON.resultDataSet[1].Msg != null && e.responseJSON.resultDataSet[1].Msg != "") {
            $c.win.alert(e.responseJSON.resultDataSet[1].Msg);
        }
    }

    //removeAll() 해도 ds_retrieveStevedoring_onrowpositionchange 이벤트를 수행하여 중지시킴
    ds_retrieveStevedoring.setEventPause("", true); // 데이터리스트 이벤트 중지
    ds_retrieveStevedoring.removeAll();
    ds_retrieveStevedoring.setEventPause("", false); // 데이터리스트 이벤트 다시 발생
    ds_retrieveStevedoring2.removeAll();

    scwin.f_Retrieve();

    scwin.rowFlag = "";
    scwin.isInsert = false;

};

