    ds_retrieveStevedoring.setCellData(ds_retrieveStevedoring.getRowPosition(), "bas004", 0);
    ds_retrieveStevedoring.setCellData(ds_retrieveStevedoring.getRowPosition(), "bas005", 0);
    ds_retrieveStevedoring.setCellData(ds_retrieveStevedoring.getRowPosition(), "bas006", "");
    ds_retrieveStevedoring.setCellData(ds_retrieveStevedoring.getRowPosition(), "scBasisUnitCd", "TON");
    ds_retrieveStevedoring.setCellData(ds_retrieveStevedoring.getRowPosition(), "scBas004", 0);
