scwin.chkRowChg = async function () {
    if (scwin.rowFlag == "") {
        if (((ds_retrieveStevedoring.getModifiedIndex().length == 0 && ds_retrieveStevedoring2.getModifiedIndex().length > 0)
            || (ds_retrieveStevedoring.getModifiedIndex().length > 0 && ds_retrieveStevedoring2.getModifiedIndex().length == 0)
            || (ds_retrieveStevedoring.getModifiedIndex().length > 0 && ds_retrieveStevedoring2.getModifiedIndex().length > 0))
            //&& scwin.isInsert == true
        ) {
            debugger;
            var confirm = await $c.win.confirm(MSG_CM_CRM_005);
            if (confirm) {
                //ds_retrieveStevedoring.undoAll();
                $c.data.undoAll(ds_retrieveStevedoring);
                //return true;
            } else {
                /*
                if(ds_retrieveStevedoring.getRowStatus(ds_retrieveStevedoring.getRowCount()-1) == "C"){
                    ds_retrieveStevedoring.removeRow(ds_retrieveStevedoring.getRowCount()-1);
                }
                */
                ds_retrieveStevedoring.setEventPause("", true);
                gr_retrieveStevedoring.setFocusedCell(info.oldRowIndex, 0);
                ds_retrieveStevedoring.setEventPause("", false);

                //alert("gr_retrieveStevedoring.getFocusedRowIndex : "+gr_retrieveStevedoring.getFocusedRowIndex());
                //return false;
            }
        }
    }
}

scwin.ds_retrieveStevedoring_onrowpositionchange = async function (info) {

    if (scwin.rowFlag == "") {
        if (((ds_retrieveStevedoring.getModifiedIndex().length == 0 && ds_retrieveStevedoring2.getModifiedIndex().length > 0)
            || (ds_retrieveStevedoring.getModifiedIndex().length > 0 && ds_retrieveStevedoring2.getModifiedIndex().length == 0)
            || (ds_retrieveStevedoring.getModifiedIndex().length > 0 && ds_retrieveStevedoring2.getModifiedIndex().length > 0))
            //&& scwin.isInsert == true
        ) {
            var confirm = await $c.win.confirm(MSG_CM_CRM_005);
            if (confirm) {
                //ds_retrieveStevedoring.undoAll();
                $c.data.undoAll(ds_retrieveStevedoring);
                //return true;
            } else {
                /*
                if(ds_retrieveStevedoring.getRowStatus(ds_retrieveStevedoring.getRowCount()-1) == "C"){
                    ds_retrieveStevedoring.removeRow(ds_retrieveStevedoring.getRowCount()-1);
                }
                */
                ds_retrieveStevedoring.setEventPause("", true);
                gr_retrieveStevedoring.setFocusedCell(info.oldRowIndex, 0);
                gr_retrieveStevedoring2.setFocusedCell(scwin.oldRowGrid2, 0);
                $p.setTimeout(function () {
                    ds_retrieveStevedoring2.setRowJSON(scwin.oldRowGrid2, scwin.json, true);
                }, { "delay": 200 }); //200->20

                ds_retrieveStevedoring.setEventPause("", false);
                //alert("gr_retrieveStevedoring.getFocusedRowIndex : "+gr_retrieveStevedoring.getFocusedRowIndex());
                //return false;
            }
        }
    }
};

